.btn-primary{flex:1;padding:12px 8px;background:#185FA5;color:#fff;border:none;border-radius:12px;font-size:13px;font-weight:600;cursor:pointer;letter-spacing:.2px}
.btn-secondary{flex:1;padding:12px 8px;background:#2A2C3C;color:#fff;border:none;border-radius:12px;font-size:13px;font-weight:600;cursor:pointer;letter-spacing:.2px}
.btn-primary:active{background:#1450a0}
.btn-secondary:active{background:#1a1c2a}
.btn-feedback{flex:1;padding:12px 8px;background:#E8F0F8;color:#1860A8;border:1px solid #B0C4DE;border-radius:12px;font-size:13px;font-weight:600;cursor:pointer;letter-spacing:.2px}
