        <option value="sus304">SUS304</option>
        <option value="aluminum">アルミ合金</option>
        <option value="cast_iron">鋳鉄 FC200</option>
        <option value="brass">真鍮</option>
        <option value="resin">エンプラ</option>
      </select>
    </div>

    <div class="chip chip-4">
      <div class="chip-badge">4</div>
      <div class="chip-text">
        <div class="chip-label">摩擦係数</div>
        <div class="chip-val" id="chip-mu-val">μ=0.15 乾燥</div>
      </div>
      <select id="mu" class="chip-select" onchange="updateChips();calc()">
        <option value="dry" selected>乾燥 (μ=0.15)</option>
        <option value="lube">潤滑 (μ=0.10)</option>
