    warnEl.classList.add('show');
    ge('warn-title').textContent='⚠️ 相手部材の強度により制限（標準値より低く設定）';
    ge('warn-detail').textContent=`JIS B 1083標準値（ボルト強度基準）: ${T_jis.toFixed(2)} N·m ／ 相手部材の許容面圧を考慮して推奨トルクを低減しています。`;
  } else {
    warnEl.classList.remove('show');
  }

  // 破損モードバー
  const maxT=failModes[failModes.length-1].F*Knd;
  ge('failure-list').innerHTML=failModes.map((fm,i)=>{
    const t=(fm.F*Knd).toFixed(2);
    const mg=(fm.F*Knd/T_rec).toFixed(2);
    const pct=((fm.F*Knd)/maxT*100).toFixed(1);
    const isDom=(i===0);
    const color=BAR_COLORS[Math.min(i,BAR_COLORS.length-1)];
    return `<div class="failure-item">
      <div class="fi-header">
        <div class="fi-name">${fm.name}${isDom?'<span class="fail-tag-red">制限</span>':''}</div>
        <div class="fi-value">${t} N·m / ${mg}×</div>
      </div>
      <div class="bar-track"><div class="bar-fill ${color}" style="width:${pct}%"></div></div>
    </div>`;
  }).join('');
}

function scrollToChips(){
  document.querySelector('.chips-grid').scrollIntoView({behavior:'smooth',block:'center'});
}

function shareResult(){
  const t=ge('res-torque').textContent;
  const r=ge('res-range').textContent;
  const d=gv('diam'),g=gv('grade'),p=CL_MAT[gv('part_mat')].name,m=MU_MAP[gv('mu')].label;
  const text=`BoltSense 締め付けトルク計算（JIS B 1083）\nM${d} / ${g} / ${p} / ${m}\n推奨トルク: ${t} N·m\n${r}`;
